#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
bool vis[100010];
int e[100010],o[100010];
struct node
{
    int x,flag,dis;
};
void bfs()
{
    memset(e,0x3f,sizeof(e));
    memset(o,0x3f,sizeof(o));
    vis[1]=1;
    queue<node> q;
    q.push((node){1,0,0});
    e[1]=0;
    while(!q.empty())
    {
        node t=q.front();
        q.pop();
        for(int i:mp[t.x])
        {
            if(t.flag==1&&t.dis+1<e[i])
            {
                node t1=(node){i,0,t.dis+1};
                q.push(t1);
                e[t1.x]=t1.dis;
            }
            else if(t.flag==0&&t.dis+1<o[i])
            {
                node t1=(node){i,1,t.dis+1};
                q.push(t1);
                o[t1.x]=t1.dis;
            }
        }
    }
}
int main()
{
    int n,m,q;
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    bfs();
    while(q--)
    {
        int a,l;
        scanf("%d%d",&a,&l);
        if(l%2==0)
        {
            if(e[a]<=l)
            {
                printf("Yes\n");
            }
            else
            {
                printf("No\n");
            }
        }
        else
        {
            if(o[a]<=l)
            {
                printf("Yes\n");
            }
            else
            {
                printf("No\n");
            }
        }
    }
    return 0;
}
